if (! function_exists('image_exif_reader')) {
    function image_exif_reader($path, $read_thumbnail = null, $sections = null, $timeout = null)
    {
        // EXIF Metadata Reader - extracts camera/photo metadata from JPEG/TIFF images
        // Uses PHP's exif extension (different from GD - reads embedded metadata)

        $path = isset($path) ? (string)$path : '';
        $read_thumbnail = isset($read_thumbnail) ? (bool)$read_thumbnail : false;
        $sections_str = isset($sections) ? (string)$sections : 'ALL';

        if ($path === '') {
            return ['error' => 'Image path is required'];
        }

        // Resolve path
        $full_path = realpath($path);
        if ($full_path === false || !file_exists($full_path)) {
            // Try relative to project root
            $project_root = realpath(__DIR__ . '/../../../..');
            $full_path = realpath($project_root . '/' . ltrim($path, '/'));
        }
        if ($full_path === false || !file_exists($full_path)) {
            return ['error' => "File not found: {$path}"];
        }

        if (!extension_loaded('exif')) {
            return ['error' => 'EXIF extension not loaded'];
        }

        if (!function_exists('exif_read_data')) {
            return ['error' => 'exif_read_data() not available'];
        }

        try {
            // Check image type
            $img_type = @exif_imagetype($full_path);
            if ($img_type === false) {
                return ['error' => 'Cannot determine image type (not a valid image)'];
            }
            
            $type_names = [
                IMAGETYPE_JPEG => 'JPEG',
                IMAGETYPE_TIFF_II => 'TIFF (Intel byte order)',
                IMAGETYPE_TIFF_MM => 'TIFF (Motorola byte order)',
            ];
            $type_name = $type_names[$img_type] ?? "Unknown (code: {$img_type})";
            
            if (!in_array($img_type, [IMAGETYPE_JPEG, IMAGETYPE_TIFF_II, IMAGETYPE_TIFF_MM])) {
                return ['error' => "EXIF data only available for JPEG/TIFF images, got: {$type_name}"];
            }
            
            // Parse sections
            $sections = [];
            foreach (explode(',', strtoupper($sections_str)) as $s) {
                $s = trim($s);
                if ($s !== '') $sections[] = $s;
            }
            $read_all = in_array('ALL', $sections);
            
            // Read EXIF data
            // Use '' for sections to get everything
            $exif_data = @exif_read_data($full_path, $read_all ? '' : implode(',', $sections), true, false);
            
            if ($exif_data === false) {
                return [
                    'success' => true,
                    'image_type' => $type_name,
                    'file_size' => filesize($full_path),
                    'message' => 'No EXIF data found in this image',
                    'has_exif' => false,
                ];
            }
            
            // Extract thumbnail if requested
            $thumbnail = null;
            if ($read_thumbnail) {
                $thumb_data = @exif_thumbnail($full_path);
                if ($thumb_data !== false) {
                    $thumb_path = dirname($full_path) . '/' . pathinfo($full_path, PATHINFO_FILENAME) . '_thumb.jpg';
                    $written = @file_put_contents($thumb_path, $thumb_data);
                    if ($written !== false) {
                        $thumbnail = [
                            'path' => $thumb_path,
                            'size_bytes' => $written,
                            'size_human' => $written >= 1024 ? round($written / 1024, 1) . ' KB' : $written . ' B',
                        ];
                    }
                }
            }
            
            // Organize the EXIF data into meaningful categories
            $organized = [];
            $camera = [];
            $exposure = [];
            $gps = [];
            $file_info = [];
            $dates = [];
            $copyright_info = [];
            $other = [];
            
            $interesting_camera = ['Make', 'Model', 'Software', 'Artist', 'CameraSerialNumber'];
            $interesting_exposure = ['ExposureTime', 'FNumber', 'ISOSpeedRatings', 'FocalLength', 'MaxApertureValue', 'MeteringMode', 'ExposureProgram', 'ExposureBiasValue', 'Flash', 'WhiteBalance', 'DigitalZoomRatio', 'SceneCaptureType'];
            $interesting_gps = ['GPSLatitude', 'GPSLatitudeRef', 'GPSLongitude', 'GPSLongitudeRef', 'GPSAltitude', 'GPSAltitudeRef', 'GPSImgDirection', 'GPSImgDirectionRef'];
            $interesting_dates = ['DateTimeOriginal', 'DateTimeDigitized', 'DateTime'];
            $interesting_copyright = ['Copyright', 'CopyrightHolder'];
            $interesting_file = ['FileName', 'FileSize', 'FileType', 'MimeType'];
            $interesting_other = ['Orientation', 'XResolution', 'YResolution', 'ResolutionUnit', 'YCbCrPositioning', 'ColorSpace', 'ComponentsConfiguration', 'Compression', 'ImageDescription', 'UserComment'];
            
            // Flatten the section-based structure
            $flat = [];
            foreach ($exif_data as $section => $items) {
                if (is_array($items)) {
                    foreach ($items as $key => $value) {
                        if (is_string($value) || is_numeric($value)) {
                            $flat[$key] = $value;
                        } elseif (is_array($value)) {
                            $flat[$key] = json_encode($value);
                        }
                    }
                } elseif (is_string($items)) {
                    $flat[$section] = $items;
                }
            }
            
            foreach ($flat as $key => $value) {
                if (in_array($key, $interesting_camera)) $camera[$key] = $value;
                elseif (in_array($key, $interesting_exposure)) $exposure[$key] = $value;
                elseif (in_array($key, $interesting_gps)) $gps[$key] = $value;
                elseif (in_array($key, $interesting_dates)) $dates[$key] = $value;
                elseif (in_array($key, $interesting_copyright)) $copyright_info[$key] = $value;
                elseif (in_array($key, $interesting_file)) $file_info[$key] = $value;
                elseif (in_array($key, $interesting_other)) $other[$key] = $value;
            }
            
            // Also include all IFD0 data (camera info)
            if (isset($exif_data['IFD0'])) {
                foreach ($exif_data['IFD0'] as $key => $value) {
                    if (is_string($value) && !isset($camera[$key]) && !isset($other[$key])) {
                        if (!str_contains($key, 'UndefinedTag')) {
                            $other[$key] = $value;
                        }
                    }
                }
            }
            
            // Process GPS coordinates into human-readable format
            $gps_lat = null;
            $gps_lon = null;
            if (isset($exif_data['GPS']['GPSLatitude']) && isset($exif_data['GPS']['GPSLatitudeRef'])) {
                $lat = $exif_data['GPS']['GPSLatitude'];
                $lat_ref = $exif_data['GPS']['GPSLatitudeRef'];
                if (is_array($lat) && count($lat) === 3) {
                    $gps_lat = gpsToDecimal($lat, $lat_ref);
                }
            }
            if (isset($exif_data['GPS']['GPSLongitude']) && isset($exif_data['GPS']['GPSLongitudeRef'])) {
                $lon = $exif_data['GPS']['GPSLongitude'];
                $lon_ref = $exif_data['GPS']['GPSLongitudeRef'];
                if (is_array($lon) && count($lon) === 3) {
                    $gps_lon = gpsToDecimal($lon, $lon_ref);
                }
            }
            
            $result = [
                'success' => true,
                'image_type' => $type_name,
                'file_size' => filesize($full_path),
                'has_exif' => true,
                'sections_found' => array_keys($exif_data),
            ];
            
            if (count($camera) > 0) $result['camera'] = $camera;
            if (count($exposure) > 0) $result['exposure'] = $exposure;
            if (count($gps) > 0) $result['gps_raw'] = $gps;
            if ($gps_lat !== null && $gps_lon !== null) {
                $result['coordinates'] = ['latitude' => $gps_lat, 'longitude' => $gps_lon];
            }
            if (count($dates) > 0) $result['dates'] = $dates;
            if (count($copyright_info) > 0) $result['copyright'] = $copyright_info;
            if (count($other) > 0) $result['other'] = $other;
            if ($thumbnail !== null) $result['thumbnail'] = $thumbnail;
            
            return $result;
            
        } catch (\Throwable $e) {
            return ['error' => 'EXIF reading failed: ' . $e->getMessage()];
        }

        // Helper: Convert GPS coordinates to decimal degrees
        function gpsToDecimal($coord, $ref) {
            if (!is_array($coord) || count($coord) < 3) return null;
            
            // coord is [degrees, minutes, seconds] as rational numbers
            $deg = is_array($coord[0]) ? ($coord[0][0] / $coord[0][1]) : (float)$coord[0];
            $min = is_array($coord[1]) ? ($coord[1][0] / $coord[1][1]) : (float)$coord[1];
            $sec = is_array($coord[2]) ? ($coord[2][0] / $coord[2][1]) : (float)$coord[2];
            
            $decimal = $deg + ($min / 60.0) + ($sec / 3600.0);
            
            if (strtoupper($ref) === 'S' || strtoupper($ref) === 'W') {
                $decimal *= -1;
            }
            
            return round($decimal, 6);
        }
    }
